  .pain-card p { color: #cc8888; font-size: 0.87rem; }

  .fix-card { background: rgba(106,153,85,0.06); border: 1px solid rgba(106,153,85,0.25); border-radius: 6px; padding: 16px 20px; margin-bottom: 10px; }
