  .tip.orange { background: rgba(230,168,23,0.07); border-color: rgba(230,168,23,0.3); }
  .tip.orange strong { color: var(--ansi-orange); }
  .tip.green { background: rgba(106,153,85,0.07); border-color: rgba(106,153,85,0.3); }
