  .flow-row { display: flex; align-items: center; gap: 10px; margin: 6px 0; font-size: 0.85rem; }
  .flow-step { background: rgba(0,0,0,0.4); border: 1px solid #333; border-radius: 4px; padding: 8px 14px; color: var(--text-main); flex: 1; }
  .flow-arrow { color: var(--ansi-cyan); font-size: 1rem; flex-shrink: 0; }
  .flow-step.highlight { border-color: rgba(79,193,255,0.4); background: rgba(14,99,156,0.1); }
  .flow-step.green { border-color: rgba(106,153,85,0.4); background: rgba(106,153,85,0.07); color: #98c080; }
  .flow-step.orange { border-color: rgba(230,168,23,0.4); background: rgba(230,168,23,0.07); color: var(--ansi-yellow); }
